python - <<'PY'
import json
from datetime import datetime

path='day16/q2_timeline.json'
with open(path,'r',encoding='utf-8') as f:
    data=json.load(f)

FIELDS={'start_date','end_date','deadline'}

def to_iso8(s):
    # Normalize various partial ISO/date strings into ISO 8601 with +08:00
    # Supported inputs in file: YYYY-MM-DD, YYYY-MM-DDTHH:MM, YYYY-MM-DDTHH:MM:SS
    # (may already have time but no tz)
    if 'T' not in s:
        dt=datetime.strptime(s,'%Y-%m-%d')
        dt=dt.replace(hour=0,minute=0,second=0)
    else:
        # try with seconds then without
        for fmt in ('%Y-%m-%dT%H:%M:%S','%Y-%m-%dT%H:%M'):
            try:
                dt=datetime.strptime(s,fmt)
                break
            except ValueError:
                dt=None
        if dt is None:
            raise ValueError(f'Unrecognized datetime format: {s}')
    return dt.strftime('%Y-%m-%dT%H:%M:%S+08:00')

def walk(obj):
    if isinstance(obj, dict):
        for k,v in list(obj.items()):
            if k in FIELDS and isinstance(v,str):
                obj[k]=to_iso8(v)
            else:
                walk(v)
    elif isinstance(obj, list):
        for item in obj:
            walk(item)

walk(data)

with open(path,'w',encoding='utf-8') as f:
    json.dump(data,f,ensure_ascii=False,indent=2)
    f.write('\n')

print('updated')
PY

